SELECT AVG(shipping_price) AS average_shipping_price
FROM shipping_rates
WHERE country_code = '1' AND region = 'Yap';

SELECT method_name 
FROM shipping_methods 
WHERE is_active = 1;

SELECT promo_id
FROM promotions
WHERE is_active = 1;

SELECT rate_id
FROM shipping_rates
WHERE is_promotional = 1;

SELECT method_name
FROM shipping_methods
WHERE method_id = 1;

SELECT * 
FROM countries
ORDER BY country_code ASC;
